+import AVFoundation
+import AppKit
+import CoreGraphics
+import Foundation
+import IOKit.hidsystem
+
+private enum PermissionEnvironment {
+    static let isRunningTests = ProcessInfo.processInfo.environment["XCTestConfigurationFilePath"] != nil
+}
+
+enum SystemSettingsPane: String, CaseIterable, Hashable {
+    case inputMonitoring = "x-apple.systempreferences:com.apple.preference.security?Privacy_ListenEvent"
+    case screenRecording = "x-apple.systempreferences:com.apple.preference.security?Privacy_ScreenCapture"
+    case accessibility = "x-apple.systempreferences:com.apple.preference.security?Privacy_Accessibility"
+    case microphone = "x-apple.systempreferences:com.apple.preference.security?Privacy_Microphone"
+
+    var url: URL {
+        URL(string: rawValue)!
+    }
+}
+
+protocol SystemSettingsOpening: Sendable {
+    func open(_ pane: SystemSettingsPane)
+}
+
+struct WorkspaceSystemSettingsOpener: SystemSettingsOpening {
+    func open(_ pane: SystemSettingsPane) {
+        guard !PermissionEnvironment.isRunningTests else {
+            return
+        }
+
+        NSWorkspace.shared.open(pane.url)
+    }
+}
+
+protocol MicrophonePermissionControlling: Sendable {
+    func ensureAccess() async -> Bool
+}
+
+struct MicrophonePermissionController: MicrophonePermissionControlling {
+    private let statusProvider: @Sendable () -> AVAuthorizationStatus
+    private let requestAccess: @Sendable () async -> Bool
+
+    init(
+        statusProvider: @escaping @Sendable () -> AVAuthorizationStatus = {
+            if PermissionEnvironment.isRunningTests {
+                return .authorized
+            }
+            return AVCaptureDevice.authorizationStatus(for: .audio)
+        },
+        requestAccess: @escaping @Sendable () async -> Bool = {
+            if PermissionEnvironment.isRunningTests {
+                return true
+            }
+            return await AVCaptureDevice.requestAccess(for: .audio)
+        }
+    ) {
+        self.statusProvider = statusProvider
+        self.requestAccess = requestAccess
+    }
+
+    func ensureAccess() async -> Bool {
+        switch statusProvider() {
+        case .authorized:
+            return true
+        case .notDetermined:
+            return await requestAccess()
+        default:
+            return false
+        }
+    }
+}
+
+protocol InputMonitoringPermissionControlling: Sendable {
+    func isGranted() -> Bool
+    @discardableResult
+    func requestAccess() -> Bool
+}
+
+struct InputMonitoringPermissionController: InputMonitoringPermissionControlling {
+    private let checkAccess: @Sendable () -> IOHIDAccessType
+    private let request: @Sendable () -> Bool
+
+    init(
+        checkAccess: @escaping @Sendable () -> IOHIDAccessType = {
+            if PermissionEnvironment.isRunningTests {
+                return kIOHIDAccessTypeGranted
+            }
+            return IOHIDCheckAccess(kIOHIDRequestTypeListenEvent)
+        },
+        request: @escaping @Sendable () -> Bool = {
+            if PermissionEnvironment.isRunningTests {
+                return true
+            }
+            return IOHIDRequestAccess(kIOHIDRequestTypeListenEvent)
+        }
+    ) {
+        self.checkAccess = checkAccess
+        self.request = request
+    }
+
+    func isGranted() -> Bool {
+        checkAccess() == kIOHIDAccessTypeGranted
+    }
+
+    @discardableResult
+    func requestAccess() -> Bool {
+        request()
+    }
+}
+
+enum ScreenRecordingPermissionState: Equatable {
+    case granted
+    case denied
+}
+
+protocol ScreenRecordingPermissionControlling: AnyObject, Sendable {
+    var state: ScreenRecordingPermissionState { get }
+    @discardableResult
+    func refresh() -> ScreenRecordingPermissionState
+    @discardableResult
+    func requestAccess() -> ScreenRecordingPermissionState
+}
+
+final class ScreenRecordingPermissionController: ScreenRecordingPermissionControlling, @unchecked Sendable {
+    private let preflight: @Sendable () -> Bool
+    private let request: @Sendable () -> Bool
+
+    private(set) var state: ScreenRecordingPermissionState
+
+    init(
+        preflight: @escaping @Sendable () -> Bool = {
+            if PermissionEnvironment.isRunningTests {
+                return true
+            }
+            return CGPreflightScreenCaptureAccess()
+        },
+        request: @escaping @Sendable () -> Bool = {
+            if PermissionEnvironment.isRunningTests {
+                return true
+            }
+            return CGRequestScreenCaptureAccess()
+        }
+    ) {
+        self.preflight = preflight
+        self.request = request
+        state = preflight() ? .granted : .denied
+    }
+
+    @discardableResult
+    func refresh() -> ScreenRecordingPermissionState {
+        state = preflight() ? .granted : .denied
+        return state
+    }
+
+    @discardableResult
+    func requestAccess() -> ScreenRecordingPermissionState {
+        _ = request()
+        return refresh()
+    }
+}

