+import AVFoundation
+import XCTest
+@testable import GhostPepper
+
+final class PermissionControllersTests: XCTestCase {
+    func testSystemSettingsPaneURLsMatchTheDocumentedPrivacyTargets() {
+        XCTAssertEqual(SystemSettingsPane.inputMonitoring.rawValue, "x-apple.systempreferences:com.apple.preference.security?Privacy_ListenEvent")
+        XCTAssertEqual(SystemSettingsPane.screenRecording.rawValue, "x-apple.systempreferences:com.apple.preference.security?Privacy_ScreenCapture")
+        XCTAssertEqual(SystemSettingsPane.accessibility.rawValue, "x-apple.systempreferences:com.apple.preference.security?Privacy_Accessibility")
+        XCTAssertEqual(SystemSettingsPane.microphone.rawValue, "x-apple.systempreferences:com.apple.preference.security?Privacy_Microphone")
+    }
+
+    func testMicrophonePermissionRequestsAccessOnlyWhenNotDetermined() async {
+        let notDetermined = MicrophonePermissionController(
+            statusProvider: { .notDetermined },
+            requestAccess: { true }
+        )
+        let denied = MicrophonePermissionController(
+            statusProvider: { .denied },
+            requestAccess: { XCTFail("Denied status should not request access"); return false }
+        )
+
+        let grantedAfterPrompt = await notDetermined.ensureAccess()
+        let deniedWithoutPrompt = await denied.ensureAccess()
+
+        XCTAssertTrue(grantedAfterPrompt)
+        XCTAssertFalse(deniedWithoutPrompt)
+    }
+
+    func testInputMonitoringPermissionUsesGrantStateAndRequestResult() {
+        let granted = InputMonitoringPermissionController(
+            checkAccess: { kIOHIDAccessTypeGranted },
+            request: { false }
+        )
+        let denied = InputMonitoringPermissionController(
+            checkAccess: { kIOHIDAccessTypeDenied },
+            request: { true }
+        )
+
+        XCTAssertTrue(granted.isGranted())
+        XCTAssertFalse(denied.isGranted())
+        XCTAssertTrue(denied.requestAccess())
+    }
+
+    func testScreenRecordingPermissionRefreshesImmediatelyAfterRequest() {
+        let responses = ScreenRecordingPreflightResponses(values: [false, true])
+        let controller = ScreenRecordingPermissionController(
+            preflight: { responses.next() },
+            request: { true }
+        )
+
+        XCTAssertEqual(controller.state, .denied)
+        XCTAssertEqual(controller.requestAccess(), .granted)
+        XCTAssertEqual(controller.state, .granted)
+    }
+}
+
+private final class ScreenRecordingPreflightResponses: @unchecked Sendable {
+    private var values: [Bool]
+
+    init(values: [Bool]) {
+        self.values = values
+    }
+
+    func next() -> Bool {
+        values.removeFirst()
+    }
+}
